DECLARE @ViewName NVARCHAR(128);
DECLARE @SQL NVARCHAR(4000);
DECLARE @ErrorMessage NVARCHAR(4000);
DECLARE @ErrorSeverity INT;

IF OBJECT_ID('tempdb..#ViewsToTest') IS NOT NULL
    DROP TABLE #ViewsToTest;

IF OBJECT_ID('tempdb..#ViewTestResults') IS NOT NULL
    DROP TABLE #ViewTestResults;

CREATE TABLE #ViewsToTest
(
    ViewName NVARCHAR(128)
);

CREATE TABLE #ViewTestResults
(
    ViewName NVARCHAR(128),
    TestResult BIT,
    ErrorMessage NVARCHAR(4000),
    ErrorSeverity INT
);

INSERT INTO #ViewsToTest
SELECT QUOTENAME(OBJECT_SCHEMA_NAME(object_id)) + '.' + QUOTENAME(name) AS [ViewName]
FROM sys.views;

WHILE EXISTS (SELECT 1 FROM #ViewsToTest)
BEGIN
    SELECT TOP 1 @ViewName = ViewName
    FROM #ViewsToTest;

    SET @SQL = N'SELECT TOP 1 1 FROM ' + @ViewName;

    BEGIN TRY
        EXEC sp_executesql @SQL;
        INSERT INTO #ViewTestResults (ViewName, TestResult)
        VALUES (@ViewName, 1);
    END TRY
    BEGIN CATCH
        SET @ErrorMessage = ERROR_MESSAGE();
        SET @ErrorSeverity = ERROR_SEVERITY();

        INSERT INTO #ViewTestResults (ViewName, TestResult, ErrorMessage, ErrorSeverity)
        VALUES (@ViewName, 0, @ErrorMessage, @ErrorSeverity);
    END CATCH;

    DELETE FROM #ViewsToTest WHERE ViewName = @ViewName;
END;

-- Query the results from #ViewTestResults table
SELECT ViewName, TestResult, ErrorMessage, ErrorSeverity
FROM #ViewTestResults;

DROP TABLE #ViewsToTest;
DROP TABLE #ViewTestResults;
